
const CACHE = 'olaprestige-v1';
const OFFLINE_HTML = '<html><head><meta charset=UTF-8><meta name=viewport content="width=device-width,initial-scale=1"><title>OlaPrestige — Hors ligne</title><style>*{margin:0;padding:0;box-sizing:border-box;}body{font-family:Nunito,sans-serif;background:#1A0508;color:#fff;min-height:100vh;display:flex;flex-direction:column;align-items:center;justify-content:center;text-align:center;padding:2rem;gap:1.2rem;}.logo{font-size:4rem;}.title{font-family:serif;font-size:2rem;font-weight:900;color:#C9A84C;}.sub{color:rgba(255,255,255,.6);font-size:.95rem;line-height:1.7;max-width:320px;}.btn{display:inline-flex;align-items:center;gap:.5rem;background:linear-gradient(135deg,#128C7E,#25D366);color:#fff;text-decoration:none;padding:.9rem 2rem;border-radius:50px;font-weight:900;font-size:1rem;margin-top:.5rem;box-shadow:0 8px 24px rgba(37,211,102,.4);}.note{color:rgba(255,255,255,.3);font-size:.75rem;}</style></head><body><div class=logo>🍽️</div><div class=title>OlaPrestige</div><p class=sub>Pas de connexion internet.<br>Commandez directement via WhatsApp !</p><a class=btn href="https://wa.me/2290152372275?text=Bonjour%20OlaPrestige%20!%20Je%20souhaite%20commander%20%F0%9F%8D%BD%EF%B8%8F">📲 Commander sur WhatsApp</a><p class=note>Ou appelez le +229 01 52 37 22 75</p></body></html>';

const PRECACHE = ['/'];

self.addEventListener('install', e => {
  e.waitUntil(
    caches.open(CACHE).then(c => c.addAll(PRECACHE).catch(()=>{})).then(() => self.skipWaiting())
  );
});

self.addEventListener('activate', e => {
  e.waitUntil(
    caches.keys().then(keys => Promise.all(keys.filter(k=>k!==CACHE).map(k=>caches.delete(k))))
    .then(() => self.clients.claim())
  );
});

self.addEventListener('fetch', e => {
  const req = e.request;
  if (req.method !== 'GET') return;
  const url = new URL(req.url);
  if (url.origin !== location.origin) return;

  if (req.headers.get('Accept')?.includes('text/html')) {
    e.respondWith(
      fetch(req).then(r => { caches.open(CACHE).then(c=>c.put(req,r.clone())); return r; })
      .catch(async () => {
        const cached = await caches.match(req);
        if (cached) return cached;
        return new Response(OFFLINE_HTML, {headers:{'Content-Type':'text/html;charset=utf-8'}});
      })
    );
    return;
  }

  if (req.destination === 'image' || url.hostname.includes('fonts.g')) {
    e.respondWith(
      caches.match(req).then(cached => {
        if (cached) return cached;
        return fetch(req).then(r => {
          if (r.ok) caches.open(CACHE).then(c=>c.put(req,r.clone()));
          return r;
        }).catch(() => new Response('',{status:503}));
      })
    );
    return;
  }

  e.respondWith(
    caches.match(req).then(cached => {
      const net = fetch(req).then(r=>{ if(r.ok) caches.open(CACHE).then(c=>c.put(req,r.clone())); return r; }).catch(()=>cached);
      return cached || net;
    })
  );
});

self.addEventListener('push', e => {
  if (!e.data) return;
  let d; try{ d=e.data.json(); }catch{ d={title:'OlaPrestige',body:e.data.text()}; }
  e.waitUntil(self.registration.showNotification(d.title||'🍽️ OlaPrestige',{
    body: d.body||'Votre commande est en route !',
    icon: 'data:image/png;base64,', badge: 'data:image/png;base64,',
    vibrate:[200,100,200],
    actions:[{action:'order',title:'📲 Commander'},{action:'close',title:'Fermer'}]
  }));
});

self.addEventListener('notificationclick', e => {
  e.notification.close();
  if (e.action==='order') { clients.openWindow('https://wa.me/2290152372275'); return; }
  e.waitUntil(clients.matchAll({type:'window'}).then(list=>{
    for(const c of list){ if('focus' in c) return c.focus(); }
    return clients.openWindow('/');
  }));
});
